const response = $input.item.json;
const topicData = $('Pick Topic').item.json;
let articleData;
try {
  articleData = JSON.parse(response.choices[0].message.content);
} catch(e) {
  throw new Error('Failed to parse LLM response: ' + e.message);
}
const { title, description, tags, body } = articleData;
const today = topicData.today;
const slug = title
  .toLowerCase()
  .replace(/[åä]/g, 'a').replace(/ö/g, 'o')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .substring(0, 60);
const tagsStr = Array.isArray(tags) ? tags.map(t => '"' + t + '"').join(', ') : '"hamn", "båtliv", "finnboda"';
const content = '---\ntitle: "' + title + '"\ndescription: "' + description + '"\npubDate: ' + today + '\ntags: [' + tagsStr + ']\n---\n\n' + body;
return [{ json: { slug, content, title, today } }];
